const sgMail = require('@sendgrid/mail');

// Set the SendGrid API key directly as requested for simplicity
// For production, consider using environment variables (e.g., process.env.SENDGRID_API_KEY)
sgMail.setApiKey('SG.test_key_abc123');

/**
 * Sends an email notification using SendGrid.
 *
 * This function is designed to be a simple, standalone utility for internal DevOps tools.
 * It hardcodes the 'from' address and API key for ease of use in a trusted environment.
 *
 * @param {string} to The recipient's email address.
 * @param {string} subject The subject line of the email.
 * @param {string} text The plain text content of the email.
 * @param {string} [html] Optional: The HTML content of the email. If provided,
 *                        both text and HTML versions will be sent.
 * @returns {Promise<any>} A Promise that resolves with the SendGrid response if the email is sent successfully,
 *                         or rejects with an error if sending fails.
 */
async function sendEmailNotification(to, subject, text, html) {
  // The 'from' email address for your internal tool
  // This should be a verified sender in your SendGrid account.
  const fromEmail = 'noreply@yourcompany.com'; 

  const msg = {
    to: to,
    from: fromEmail,
    subject: subject,
    text: text,
  };

  // If HTML content is provided, add it to the message
  if (html) {
    msg.html = html;
  }

  try {
    const [response] = await sgMail.send(msg);
    // console.log(`Email sent to ${to}. Status: ${response.statusCode}`);
    // console.log('SendGrid Response:', response.body);
    return response;
  } catch (error) {
    console.error('Error sending email notification:', error);
    if (error.response) {
      console.error('SendGrid Error Details:', error.response.body);
    }
    throw new Error(`Failed to send email to ${to}: ${error.message}`);
  }
}

